/**
 * LayerInfinite MCP Server — index.ts
 * ══════════════════════════════════════════════════════════════
 * V2 Gateway Proxy entry point. Uses low-level Server (ADR-001)
 * for raw JSON-RPC interception of tools/list and tools/call.
 *
 * Registers handlers:
 *   tools/list   — enriched upstream tools + virtual li_recommend
 *   tools/call   — proxy to upstream, auto-mode rerouting
 *   resources/*  — gateway status + config (admin-gated)
 *   prompts/*    — setup instructions
 * ══════════════════════════════════════════════════════════════
 */

import { Server } from '@modelcontextprotocol/sdk/server/index.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from '@modelcontextprotocol/sdk/types.js';

import { loadConfig } from './config.js';
import type { GatewayConfig } from './config.js';
import { LiApiClient, UpstreamMCPClient } from './rest-client.js';
import { UpstreamRegistry } from './upstream-registry.js';
import { GatewayProxy } from './gateway-proxy.js';
import { OutcomeClassifier } from './outcome-classifier.js';
import { logger } from './logger.js';

const SERVER_NAME = 'layerinfinite-gateway';
const SERVER_VERSION = '2.0.0';

const log = logger.forTool('index');

// ── Task context extraction ─────────────────────────────────

interface TaskContext {
  taskType: string;
  customerId: string;
  agentId: string;
}

function extractTaskContext(params: Record<string, unknown> | undefined): TaskContext {
  const args = (params?.['arguments'] as Record<string, unknown>) ?? {};
  const meta = (params?.['_meta'] as Record<string, unknown>) ?? {};

  const taskType = String(
    args['task_type'] ?? args['taskType'] ?? params?.['task_type'] ?? meta['taskType'] ?? 'unknown',
  );

  const customerId = String(
    args['customer_id'] ??
      args['customerId'] ??
      params?.['customer_id'] ??
      process.env.LAYERINFINITE_DEFAULT_CUSTOMER ??
      'default',
  );

  const agentId = String(
    meta['agentId'] ??
      args['agent_id'] ??
      args['agentId'] ??
      params?.['agent_id'] ??
      process.env.LAYERINFINITE_DEFAULT_AGENT ??
      'unknown',
  );

  return { taskType, customerId, agentId };
}

// ══════════════════════════════════════════════════════════════
// createGatewayServer
// ══════════════════════════════════════════════════════════════

export interface GatewayServer {
  server: Server;
  proxy: GatewayProxy;
  config: GatewayConfig;
  upstreamClient: UpstreamMCPClient;
  registry: UpstreamRegistry;

/**
 * LayerInfinite API — llm-coach.ts
 * ══════════════════════════════════════════════════════════════
 * LLM-based coaching that fires on failed actions.
 *
 * Model: gpt-4o-mini (~$0.15/1M input tokens)
 * Cap:    3 coaching injections per agent session
 * Retire: when task_type has ≥ 50 historical outcomes
 * Timeout: 3s — on timeout, agent proceeds without coaching
 *
 * Integration point: called from the MCP gateway's enrichment
 * engine when an agent reports a failure. The coaching message
 * is injected into the next tools/list enrichment as a
 * "LI Note:" prefix.
 * ══════════════════════════════════════════════════════════════
 */

import { coachTracker } from './coach-session-tracker.js';
import type { ActionScore } from './supabase.js';

// ── Types ──────────────────────────────────────────────────────

export interface CoachingInput {
  agentId: string;
  customerId: string;
  /** The task the agent was attempting (e.g. "build_failed"). */
  taskType: string;
  /** The action that just failed. */
  failedActionName: string;
  /** Error details if available. */

