1	/**
2	 * LayerInfinite MCP Server — gateway-proxy.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Core V2 Gateway Proxy. Intercepts tools/list (pre-reasoning
5	 * enrichment) and tools/call (proxy to upstream + auto-mode
6	 * rerouting). Natural language enrichment per mode — never
7	 * bracketed metadata.
8	 *
9	 * Phase 2 refactor: delegates enrichment to tool-enrichment.ts,
10	 * mode resolution to mode-manager.ts, score fetching to
11	 * score-fetcher.ts, and li_recommend to li-recommend-tool.ts.
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import type { GatewayConfig } from './config.js';
16	import type {
17	  EnrichedTool,
18	  EnrichmentContext,
19	  OutcomePayload,
20	  GatewayMode,
21	} from './types.js';
22	import type { LiApiClient, UpstreamMCPClient, UpstreamCallResult } from './rest-client.js';
23	import type { UpstreamRegistry } from './upstream-registry.js';
24	import { enqueueOutcome } from './fail-open.js';
25	import { enrichToolList } from './tool-enrichment.js';
26	import { ModeManager } from './mode-manager.js';
27	import { ScoreFetcher } from './enrichment/score-fetcher.js';
28	import { createLiRecommendTool, handleLiRecommend } from './li-recommend-tool.js';
29	import { generateDecisionId } from './decision-tracker.js';
30	export { generateDecisionId };
31	import { OutcomeClassifier } from './outcome-classifier.js';
32	import type { OutcomeClassification } from './types.js';
33	import { logger } from './logger.js';
34	
35	const log = logger.forTool('gateway-proxy');
36	
37	// ── Auto-mode reroute threshold ─────────────────────────────
38	
39	const REROUTE_CONFIDENCE_THRESHOLD = 0.3;
40	
41	// ── Merge helper for agent-explicit > LLM-inferred > defaults ──
42	
43	function resolveMergeField(
44	  agentValue: string,
45	  llmValue: string | null,
46	  opts?: { exclude?: Set<string> },
47	): string | null {
48	  const exclude = opts?.exclude;
49	  if (agentValue && !exclude?.has(agentValue)) return agentValue;
50	  if (llmValue && !exclude?.has(llmValue)) return llmValue;
51	  return null;
52	}
53	
54	// ══════════════════════════════════════════════════════════════
55	// GatewayProxy
56	// ══════════════════════════════════════════════════════════════
57	
58	export class GatewayProxy {
59	  private readonly modeManager: ModeManager;
60	  private readonly scoreFetcher: ScoreFetcher;
61	
62	  constructor(
63	    private readonly liApi: LiApiClient,
64	    private readonly upstreamClient: UpstreamMCPClient,
65	    private readonly registry: UpstreamRegistry,
66	    private readonly config: GatewayConfig,
67	    private readonly classifier: OutcomeClassifier | null = null,
68	  ) {
69	    this.modeManager = new ModeManager(config);
70	    this.scoreFetcher = new ScoreFetcher(liApi);
71	  }
72	
73	  // ── tools/list handler ───────────────────────────────────
74	
75	  async handleListTools(taskContext: {
76	    taskType: string;
77	    customerId: string;
78	    agentId: string;
79	  }): Promise<EnrichedTool[]> {
80	    const mode = this.modeManager.resolveMode(taskContext.taskType);
81	
82	    try {
83	      const [rawTools, context] = await Promise.all([
84	        this.upstreamClient.listTools(),
85	        this.getEnrichmentContext(taskContext.taskType, taskContext.customerId, taskContext.agentId, mode),
86	      ]);
87	
88	      const enriched = enrichToolList(rawTools, context);
89	
90	      // Inject virtual li_recommend tool (only in non-bootstrap modes)
91	      if (mode !== 'bootstrap') {
92	        enriched.push(createLiRecommendTool());
93	      }
94	
95	      // Sort: ranked first, then alphabetically
96	      enriched.sort((a, b) => {
97	        const rankA = a.annotations?.ranking ?? 999;
98	        const rankB = b.annotations?.ranking ?? 999;
99	        if (rankA !== rankB) return rankA - rankB;
100	        return a.name.localeCompare(b.name);
101	      });
102	
103	      log.debug('tools/list enriched', {
104	        count: enriched.length,
105	        mode,
106	        taskType: taskContext.taskType,
107	      });
108	
109	      return enriched;
110	    } catch (err) {
111	      log.error('tools/list failed', { error: err instanceof Error ? err.message : String(err) });
112	      // Degrade: return raw tools with no enrichment
113	      try {
114	        const rawTools = await this.upstreamClient.listTools();
115	        return rawTools.map((t) => ({
116	          name: t.name,
117	          description: t.description,
118	          inputSchema: t.inputSchema,
119	          upstreamName: t.upstreamName,
120	        }));
121	      } catch {
122	        return [];
123	      }
124	    }
125	  }
126	
127	  // ── tools/call handler ───────────────────────────────────
128	
129	  async handleCallTool(
130	    toolName: string,
131	    args: Record<string, unknown>,
132	    taskContext: { taskType: string; customerId: string; agentId: string },
133	  ): Promise<UpstreamCallResult> {
134	    const decisionId = generateDecisionId(taskContext.agentId);
135	    const mode = this.modeManager.resolveMode(taskContext.taskType);
136	    const startMs = Date.now();
137	
138	    // Handle virtual li_recommend tool (delegated to li-recommend-tool.ts)
139	    if (toolName === 'li_recommend') {
140	      return handleLiRecommend(
141	        this.liApi,
142	        taskContext.taskType,
143	        taskContext.customerId,
144	        taskContext.agentId,
145	      );
146	    }
147	
148	    // Determine which tool to execute (auto-mode may reroute)
149	    let executedAction = toolName;
150	    let originalAction = toolName;
151	    let rerouted = false;
152	    let enrichmentScores: Record<string, number> = {};
153	
154	    if (mode === 'auto' && !this.config.shadowMode) {
155	      try {
156	        const [scores, policy] = await Promise.all([
157	          this.scoreFetcher.getScores(taskContext.taskType, taskContext.customerId, taskContext.agentId),
158	          this.liApi.getPolicyDecision(taskContext.taskType, taskContext.customerId, taskContext.agentId),
159	        ]);
160	
161	        for (const s of scores) {
162	          enrichmentScores[s.actionName] = s.compositeScore;
163	        }
164	
165	        if (
166	          policy &&
167	          policy.confidence >= REROUTE_CONFIDENCE_THRESHOLD &&
168	          policy.action !== toolName &&
169	          this.registry.isHealthy(this.resolveUpstream(policy.action))
170	        ) {
171	          originalAction = toolName;
172	          executedAction = policy.action;
173	          rerouted = true;
174	          log.info('Auto-mode reroute', {
175	            decisionId,
176	            from: toolName,
177	            to: policy.action,
178	            confidence: policy.confidence,
179	            reason: policy.reason,
180	          });
181	        }
182	      } catch {
183	        // Degrade — continue with original tool
184	      }
185	    }
186	
187	    // Resolve upstream from tool name
188	    const upstreamName = this.resolveUpstream(executedAction);
189	
190	    // Proxy to upstream
191	    const result = await this.upstreamClient.callTool(upstreamName, executedAction, args);
192	
193	    // Fire-and-forget outcome logging
194	    const latencyMs = Date.now() - startMs;
195	    void this.logDecision({
196	      decisionId,
197	      agentId: taskContext.agentId,
198	      customerId: taskContext.customerId,
199	      taskType: taskContext.taskType,
200	      actionName: executedAction,
201	      upstreamName,
202	      originalAction,
203	      executedAction,
204	      mode,
205	      rerouted,
206	      enrichmentScores,
207	      latencyMs,
208	      args,
209	      result,
210	      isError: result.isError === true,
211	    });
212	
213	    return result;
214	  }
215	
216	  // ── Shutdown ─────────────────────────────────────────────
217	
218	  async shutdown(): Promise<void> {
219	    this.registry.stopHealthChecks();
220	    log.info('Gateway proxy shut down');
221	  }
222	
223	  // ── Private: enrichment context ──────────────────────────
224	
225	  private async getEnrichmentContext(
226	    taskType: string,
