1	/**
2	 * LayerInfinite MCP Server — outcome-classifier.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * LLM-based outcome classifier using GPT-4o mini. Classifies raw
5	 * tool calls into structured OutcomeClassification when the agent
6	 * does not provide explicit task_type / context / business_outcome.
7	 *
8	 * Fail-open: LLM timeout or error → null (caller falls back to
9	 * existing rule-based defaults). Never blocks the gateway.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { createHash } from 'node:crypto';
14	import type { ClassifierConfig } from './config.js';
15	import type { OutcomeClassification } from './types.js';
16	import type { UpstreamCallResult } from './rest-client.js';
17	import { logger } from './logger.js';
18	
19	const log = logger.forTool('outcome-classifier');
20	
21	const SYSTEM_PROMPT = [
22	  'You are an outcome classifier. Given a tool call and its result, extract structured fields.',
23	  'Classify the task_type from this taxonomy: payment_failed, refund_processing, subscription_management, ticket_resolution, auth_recovery, order_recovery, onboarding, code_deployment, data_query, content_generation, web_search, file_operation, system_diagnostic, unspecified_issue.',
24	  'Determine business_outcome: resolved (success), partial (mixed/partial success), failed (error/unsuccessful), unknown (unclear).',
25	  'Output ONLY valid JSON matching the schema. No explanation.',
26	].join(' ');
27	
28	const TAXONOMY = new Set([
29	  'payment_failed', 'refund_processing', 'subscription_management',
30	  'ticket_resolution', 'auth_recovery', 'order_recovery',
31	  'onboarding', 'code_deployment', 'data_query', 'content_generation',
32	  'web_search', 'file_operation', 'system_diagnostic', 'unspecified_issue',
33	]);
34	
35	const VALID_OUTCOMES = new Set(['resolved', 'partial', 'failed', 'unknown']);
36	
37	// ── Helpers ────────────────────────────────────────────────────
38	
39	function truncateResult(result: UpstreamCallResult, maxChars: number): string {
40	  const texts: string[] = [];
41	  for (const item of result.content) {
42	    if (typeof item.text === 'string') texts.push(item.text);
43	    else if (typeof item.data === 'string') texts.push(item.data);
44	    else texts.push(JSON.stringify(item));
45	  }
46	  let joined = texts.join('\n');
47	  if (joined.length > maxChars) {
48	    joined = joined.slice(0, maxChars) + '…';
49	  }
50	  return joined;
51	}
52	
53	function makeSignature(toolName: string, args: Record<string, unknown>): string {
54	  const normalized = JSON.stringify(args, Object.keys(args).sort());
55	  const hash = createHash('sha256').update(`${toolName}:${normalized}`).digest('hex');
56	  return hash.slice(0, 16);
57	}
58	
59	function isValidClassification(o: unknown): o is OutcomeClassification {
60	  if (!o || typeof o !== 'object') return false;
61	  const c = o as Record<string, unknown>;
62	  return (
63	    typeof c.task_type === 'string' &&
64	    TAXONOMY.has(c.task_type) &&
65	    typeof c.context === 'string' &&
66	    typeof c.success === 'boolean' &&
67	    (c.error_message === null || typeof c.error_message === 'string') &&
68	    typeof c.result_summary === 'string' &&
69	    typeof c.business_outcome === 'string' &&
70	    VALID_OUTCOMES.has(c.business_outcome) &&
71	    typeof c.confidence === 'number' &&
72	    c.confidence >= 0 &&
73	    c.confidence <= 1
74	  );
75	}
76	
77	// ══════════════════════════════════════════════════════════════
78	// OutcomeClassifier
79	// ══════════════════════════════════════════════════════════════
80	
81	export class OutcomeClassifier {
82	  private readonly config: ClassifierConfig;
83	  private readonly cache = new Map<string, { storedAt: number; value: OutcomeClassification }>();
84	  private readonly inFlight = new Map<string, Promise<OutcomeClassification | null>>();
85	
86	  constructor(config: ClassifierConfig) {
87	    this.config = config;
88	  }
89	
90	  async classify(
91	    toolName: string,
92	    args: Record<string, unknown>,
93	    result: UpstreamCallResult,
94	    isError: boolean,
95	    agentTaskType: string,
96	  ): Promise<OutcomeClassification | null> {
97	    // Skip LLM if agent provided a valid explicit task_type
98	    const isExplicitTaskType = agentTaskType !== 'unknown'
99	      && agentTaskType !== ''
100	      && agentTaskType !== 'unspecified_issue';
101	
102	    if (isExplicitTaskType && !result.isError) {
103	      return null; // Agent knows best — no LLM needed for healthy calls
104	    }
105	
106	    // For error cases, always run classification regardless of agent task_type
107	    // The LLM can extract error_message and determine business_outcome accurately
108	
109	    const sig = makeSignature(toolName, args);
110	    const cacheKey = `${sig}:${isError}`;
111	
112	    // Check LRU cache
113	    const cached = this.cache.get(cacheKey);
114	    if (cached && (Date.now() - cached.storedAt) < this.config.cacheTtlMs) {
115	      log.debug('Cache hit', { toolName, cacheKey });
116	      return cached.value;
117	    }
118	
119	    // In-flight coalescing
120	    const inFlight = this.inFlight.get(cacheKey);
121	    if (inFlight) {
122	      log.debug('In-flight coalesce', { toolName, cacheKey });
123	      return inFlight;
124	    }
125	
126	    const promise = this.callLLM(toolName, args, result, isError, agentTaskType);
127	    this.inFlight.set(cacheKey, promise);
128	
129	    try {
130	      const classification = await promise;
131	      if (classification) {
132	        this.cache.set(cacheKey, { storedAt: Date.now(), value: classification });
133	      }
134	      return classification;
135	    } finally {
136	      this.inFlight.delete(cacheKey);
137	    }
138	  }
139	
140	  // ── Private ──────────────────────────────────────────────────
141	
142	  private async callLLM(
143	    toolName: string,
144	    args: Record<string, unknown>,
145	    result: UpstreamCallResult,
146	    isError: boolean,
147	    agentTaskType: string,
148	  ): Promise<OutcomeClassification | null> {
149	    if (!this.config.apiKey) {
150	      log.warn('Classifier enabled but no API key configured — skipping');
151	      return null;
152	    }
153	
154	    const controller = new AbortController();
155	    const timeout = setTimeout(() => controller.abort(), this.config.timeoutMs);
156	
157	    try {
158	      const userPrompt = JSON.stringify({
159	        tool_name: toolName,
160	        arguments: args,
161	        result: truncateResult(result, 2000),
162	        is_error: isError || result.isError === true,
163	        agent_task_type: agentTaskType,
164	      });
165	
166	      const response = await fetch(`${this.config.baseUrl}/chat/completions`, {
167	        method: 'POST',
168	        headers: {
169	          'Authorization': `Bearer ${this.config.apiKey}`,
170	          'Content-Type': 'application/json',
171	        },
172	        body: JSON.stringify({
173	          model: this.config.model,
174	          messages: [
175	            { role: 'system', content: SYSTEM_PROMPT },
176	            { role: 'user', content: userPrompt },
177	          ],
178	          temperature: 0,
179	          max_tokens: 1024,
180	          response_format: { type: 'json_object' },
181	        }),
182	        signal: controller.signal,
183	      });
184	
185	      if (!response.ok) {
186	        const text = await response.text().catch(() => '');
187	        log.warn('LLM API error', { status: response.status, text: text.slice(0, 200) });
188	        return null;
189	      }
190	
191	      const data = (await response.json()) as {
192	        choices?: Array<{ message?: { content?: string } }>;
193	      };
194	
195	      const rawContent = data.choices?.[0]?.message?.content;
196	      if (!rawContent) {
197	        log.warn('LLM returned empty response');
198	        return null;
199	      }
200	
201	      let parsed: unknown;
202	      try {
203	        parsed = JSON.parse(rawContent);
204	      } catch {
205	        log.warn('LLM returned invalid JSON', { raw: rawContent.slice(0, 200) });
