/**
 * LayerInfinite MCP Server — fail-open.ts
 * ══════════════════════════════════════════════════════════════
 * 3-Layer failure protection with circuit breaker.
 *
 * Layer 1: Async logging fails → write to local disk queue → retry with backoff
 * Layer 2: LI API unreachable → fail open → agent executes directly → queue on disk
 * Layer 3: Everything fails → agent executes as if LI doesn't exist → zero footprint
 *
 * Circuit breaker: 3 consecutive upstream failures → open for 60s → half-open probe
 * ══════════════════════════════════════════════════════════════
 */

import { writeFile, mkdir, readFile, unlink } from 'node:fs/promises';
import { join } from 'node:path';
import { randomUUID } from 'node:crypto';
import type { FailOpenState, OutcomePayload } from './types.js';
import { logger } from './logger.js';

const log = logger.forTool('fail-open');

const QUEUE_DIR = '.li-queue';
const CIRCUIT_BREAKER_THRESHOLD = 3;
const CIRCUIT_BREAKER_OPEN_MS = 60_000;
const MAX_QUEUE_RETRY_MS = 300_000; // 5 min max retry
const BASE_BACKOFF_MS = 1000;

export function createFailOpenState(): FailOpenState {
  return {
    upstreamFailures: new Map(),
    circuitBreakerOpen: new Map(),
    lastHealthCheck: new Map(),
    totalRequests: 0,
    passthroughRequests: 0,
  };
}

/** Ensure queue directory exists. Returns the directory path. */
async function ensureQueueDir(): Promise<string> {
  await mkdir(QUEUE_DIR, { recursive: true });
  return QUEUE_DIR;
}

// ── Layer 1: Disk queue for failed async logs ────────────────

export interface QueuedEntry {
  id: string;
  payload: OutcomePayload;
  attempts: number;
  firstAttempt: number;
  lastAttempt: number;
}

/**
 * Write an outcome to the local disk queue when LI API is unreachable.
 * Each entry is a separate JSON file for atomicity.
 */
export async function enqueueOutcome(payload: OutcomePayload): Promise<void> {
  const dir = await ensureQueueDir();
  const id = randomUUID();
  const entry: QueuedEntry = {
    id,
    payload,
    attempts: 0,
    firstAttempt: Date.now(),
    lastAttempt: Date.now(),
  };
  const path = join(dir, `${id}.json`);
  await writeFile(path, JSON.stringify(entry) + '\n', 'utf-8');
  log.info('Outcome queued to disk', { id, action: payload.action_name });
}

/** List all queued entries sorted by first attempt (oldest first). */
export async function listQueuedEntries(): Promise<QueuedEntry[]> {
  const { readdir } = await import('node:fs/promises');
  const dir = await ensureQueueDir();
  const entries: QueuedEntry[] = [];
  try {
    const files = await readdir(dir);
    for (const file of files) {
      if (!file.endsWith('.json')) continue;
      try {
        const content = await readFile(join(dir, file), 'utf-8');
        entries.push(JSON.parse(content) as QueuedEntry);
      } catch {
        // Corrupt queue file — skip
      }
    }
  } catch {
    // Directory doesn't exist yet — no entries
  }
  return entries.sort((a, b) => a.firstAttempt - b.firstAttempt);
}

/** Remove a queued entry by ID. */
export async function dequeueEntry(id: string): Promise<void> {
  const dir = await ensureQueueDir();
  try {
    await unlink(join(dir, `${id}.json`));
  } catch {
    // Already removed — fine
  }
}

/** Update attempts on a queued entry. */
export async function updateQueuedEntry(entry: QueuedEntry): Promise<void> {
  const dir = await ensureQueueDir();
  await writeFile(join(dir, `${entry.id}.json`), JSON.stringify(entry) + '\n', 'utf-8');
}

// ── Layer 2 & 3: Circuit breaker ─────────────────────────────

/** Record a failure for an upstream server. Returns true if circuit breaker just opened. */
export function recordUpstreamFailure(state: FailOpenState, upstreamName: string): boolean {
  const current = state.upstreamFailures.get(upstreamName) ?? 0;
  const next = current + 1;
  state.upstreamFailures.set(upstreamName, next);

  if (next >= CIRCUIT_BREAKER_THRESHOLD && !state.circuitBreakerOpen.get(upstreamName)) {
    state.circuitBreakerOpen.set(upstreamName, true);
    log.warn('Circuit breaker opened', { upstream: upstreamName, failures: next });
    return true;
  }
  return false;
}

/** Record a success — resets failure count and closes circuit breaker. */
export function recordUpstreamSuccess(state: FailOpenState, upstreamName: string): void {
  state.upstreamFailures.set(upstreamName, 0);
  if (state.circuitBreakerOpen.get(upstreamName)) {
    state.circuitBreakerOpen.set(upstreamName, false);
    log.info('Circuit breaker closed', { upstream: upstreamName });
  }
}

/** Probe half-open: check if enough time has passed to attempt a probe.
 *  Does NOT reset state — the caller must call recordUpstreamSuccess/Failure
 *  after the actual health check completes. */
export function probeCircuitBreaker(state: FailOpenState, upstreamName: string): boolean {
  const open = state.circuitBreakerOpen.get(upstreamName);
  if (!open) return false;

  const lastCheck = state.lastHealthCheck.get(upstreamName) ?? 0;
  if (Date.now() - lastCheck < CIRCUIT_BREAKER_OPEN_MS) return false;

  // Allow one probe through — caller is responsible for recording result
  state.circuitBreakerOpen.set(upstreamName, false);
  log.info('Circuit breaker half-open — probing', { upstream: upstreamName });
  return true;
}

/** Check if circuit breaker is open for an upstream. */
export function isCircuitOpen(state: FailOpenState, upstreamName: string): boolean {
  return state.circuitBreakerOpen.get(upstreamName) ?? false;
}

/** Update health check timestamp. */
export function updateHealthCheck(state: FailOpenState, upstreamName: string): void {
  state.lastHealthCheck.set(upstreamName, Date.now());
}

// ── Retry queue processor ────────────────────────────────────

export type QueueSender = (payload: OutcomePayload) => Promise<boolean>;

/**
 * Process the disk queue with exponential backoff.
 * Returns the number of entries successfully sent.
 */
export async function processQueue(send: QueueSender): Promise<number> {
  const entries = await listQueuedEntries();
  let sent = 0;

  for (const entry of entries) {
    const elapsed = Date.now() - entry.firstAttempt;
    if (elapsed > MAX_QUEUE_RETRY_MS) {
      log.warn('Queue entry expired', { id: entry.id, elapsed_ms: elapsed });
      await dequeueEntry(entry.id);
      continue;
    }

    const success = await send(entry.payload);
    if (success) {
      await dequeueEntry(entry.id);
      sent++;
    } else {
      const updated: QueuedEntry = {
        ...entry,
        attempts: entry.attempts + 1,
        lastAttempt: Date.now(),
      };
      await updateQueuedEntry(updated);
    }
  }

  return sent;
}

/**
 * Calculate backoff delay for a queue retry.
 * Exponential: min(base * 2^attempts, 5 min).
 */
export function backoffDelay(attempts: number): number {
  return Math.min(BASE_BACKOFF_MS * Math.pow(2, attempts), MAX_QUEUE_RETRY_MS);
}

/** Get queue stats for monitoring. */
export async function getQueueStats(): Promise<{ count: number; oldestMs: number | null }> {
  const entries = await listQueuedEntries();
  return {
    count: entries.length,
    oldestMs: entries.length > 0 ? Date.now() - entries[0].firstAttempt : null,
  };
}

/**
 * LayerInfinite MCP Server — types.ts
 * ══════════════════════════════════════════════════════════════
 * Shared domain types for the V2 Gateway Proxy.
 * Imports config types from config.ts; defines gateway-specific types here.
 * ══════════════════════════════════════════════════════════════
 */

import type { LIMode } from './config.js';

/** Gateway operating mode (bootstrap = mode null, observe only). */
export type GatewayMode = 'bootstrap' | LIMode;

/** Enriched tool returned by tools/list interception. */
export interface EnrichedTool {
  name: string;
  /** ENRICHED description — original woven with historical context. Never modify inputSchema. */
  description: string;
  /** UNMODIFIED — passthrough from upstream. */
  inputSchema: Record<string, unknown>;
  /** Which upstream server owns this tool. */
  upstreamName: string;
  annotations?: {
    /** 1-based rank within task (best=1). */
    ranking?: number;
    category?: 'recommended' | 'neutral' | 'warning';
  };
}

/** Context gathered before enriching tool descriptions. */
export interface EnrichmentContext {
  taskType: string;
  customerId: string;
  agentId: string;
  mode: GatewayMode;
  scores: ScoredAction[];
  policyDecision: PolicyDecision | null;
}

/** A scored action from the LI scoring engine. */
export interface ScoredAction {
  actionName: string;
  compositeScore: number;
  successRate: number;
  sampleSize: number;
  trendLabel?: string;
}

/** Policy decision from the LI policy engine. */
export interface PolicyDecision {
  action: string;
  reason: string;
  confidence: number;
}

/** A decision record — one tool invocation tracked by the gateway. */
export interface DecisionRecord {
  /** Format: dec_{ts12}_{agent4}_{rand4} — lexicographically sortable. */
  decisionId: string;
  agentId: string;
  customerId: string;
  taskType: string;
  actionName: string;
  upstreamName: string;
  /** What the agent chose. */
  originalAction: string;
  /** What actually ran (may differ in Auto mode). */
  executedAction: string;
  mode: GatewayMode;
  rerouted: boolean;
  enrichmentScores: Record<string, number>;
  /** ISO 8601 timestamp. */
  timestamp: string;
}

/** An episode — a session containing multiple decisions. */
export interface Episode {
  episodeId: string;
  agentId: string;
  sessionStart: string;
  /** Ordered list of decisionIds. */
  decisions: string[];
  /** Max 3 coachings per episode. */
  coachingCount: number;
}

/** Webhook callback from Layer 2 (session) or Layer 3 (business). */
export interface WebhookCallback {
  decisionId: string;
  /** 2 = session outcome, 3 = business outcome. */
  layer: 2 | 3;
  success: boolean;
  reason?: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/** MCP resource definition for gateway resources. */
export interface Resource {
  uri: string;
  name: string;
  description: string;
  mimeType: string;
  handler: () => Promise<{
    contents: Array<{ uri: string; mimeType: string; text: string }>;
  }>;
}

/** MCP prompt definition for gateway prompts. */
export interface Prompt {
  name: string;
  description: string;
  arguments: Array<{ name: string; description?: string; required?: boolean }>;
  handler: () => Promise<{
    messages: Array<{
      role: 'user' | 'assistant';
      content: { type: 'text'; text: string };
    }>;
  }>;
}

/** LLM-inferred outcome classification. Agent-explicit fields override LLM. */
export interface OutcomeClassification {
  task_type: string;
  context: string;
  success: boolean;
  error_message: string | null;
  result_summary: string;
  business_outcome: 'resolved' | 'partial' | 'failed' | 'unknown';
  confidence: number;
}

/** In-memory fail-open state for circuit breaker + health tracking. */
export interface FailOpenState {
  upstreamFailures: Map<string, number>;
  circuitBreakerOpen: Map<string, boolean>;
  lastHealthCheck: Map<string, number>;
  totalRequests: number;
  passthroughRequests: number;
}

/** Outcome payload sent to LI API for logging. Fields match the API's LogOutcomeBody schema. */
export interface OutcomePayload {
  /** Internal decision ID (dec_ format) — NOT sent to API (API expects UUID). */
  decision_id?: string;
  agent_id: string;
  customer_id: string;
  /** Maps to API's `issue_type` field. */
  issue_type: string;
  action_name: string;
  upstream_name: string;
  original_action: string;
  executed_action: string;
  mode: string;
  rerouted: boolean;
  /** Required by API. Defaults to true for fire-and-forget gateway logging. */
  success: boolean;
  /** Maps to API's `response_time_ms` field. */
  response_time_ms: number;
  timestamp: string;
  ingestion_source: 'mcp';
  environment: string;
  /** LLM-inferred: what the tool call was about. */
  context?: string;
  /** LLM-inferred: error message if the tool call failed. */
  error_message?: string | null;
  /** LLM-inferred: human-readable result summary. */
  result_summary?: string;
  /** LLM-inferred: business outcome classification. */
  business_outcome?: string;
  /** LLM-inferred: confidence of the classification (0-1). */
  classification_confidence?: number;
}

/**
 * LayerInfinite MCP Server — gateway-proxy.ts
 * ══════════════════════════════════════════════════════════════
 * Core V2 Gateway Proxy. Intercepts tools/list (pre-reasoning
 * enrichment) and tools/call (proxy to upstream + auto-mode
 * rerouting). Natural language enrichment per mode — never
 * bracketed metadata.
 *
 * Phase 2 refactor: delegates enrichment to tool-enrichment.ts,
 * mode resolution to mode-manager.ts, score fetching to
 * score-fetcher.ts, and li_recommend to li-recommend-tool.ts.
 * ══════════════════════════════════════════════════════════════
 */

import type { GatewayConfig } from './config.js';
import type {
  EnrichedTool,
  EnrichmentContext,
  OutcomePayload,
  GatewayMode,
} from './types.js';
import type { LiApiClient, UpstreamMCPClient, UpstreamCallResult } from './rest-client.js';
import type { UpstreamRegistry } from './upstream-registry.js';
import { enqueueOutcome } from './fail-open.js';
import { enrichToolList } from './tool-enrichment.js';
import { ModeManager } from './mode-manager.js';
import { ScoreFetcher } from './enrichment/score-fetcher.js';
import { createLiRecommendTool, handleLiRecommend } from './li-recommend-tool.js';
import { generateDecisionId } from './decision-tracker.js';
export { generateDecisionId };
import { OutcomeClassifier } from './outcome-classifier.js';
import type { OutcomeClassification } from './types.js';
import { logger } from './logger.js';

const log = logger.forTool('gateway-proxy');

// ── Auto-mode reroute threshold ─────────────────────────────

const REROUTE_CONFIDENCE_THRESHOLD = 0.3;

// ── Merge helper for agent-explicit > LLM-inferred > defaults ──

function resolveMergeField(
  agentValue: string,
  llmValue: string | null,
  opts?: { exclude?: Set<string> },
): string | null {
  const exclude = opts?.exclude;
  if (agentValue && !exclude?.has(agentValue)) return agentValue;
  if (llmValue && !exclude?.has(llmValue)) return llmValue;
  return null;
}

// ══════════════════════════════════════════════════════════════
// GatewayProxy
// ══════════════════════════════════════════════════════════════

export class GatewayProxy {
  private readonly modeManager: ModeManager;
  private readonly scoreFetcher: ScoreFetcher;

  constructor(
    private readonly liApi: LiApiClient,
    private readonly upstreamClient: UpstreamMCPClient,
    private readonly registry: UpstreamRegistry,
    private readonly config: GatewayConfig,
    private readonly classifier: OutcomeClassifier | null = null,
  ) {
    this.modeManager = new ModeManager(config);
    this.scoreFetcher = new ScoreFetcher(liApi);
  }

  // ── tools/list handler ───────────────────────────────────

  async handleListTools(taskContext: {
    taskType: string;
    customerId: string;
    agentId: string;
  }): Promise<EnrichedTool[]> {
    const mode = this.modeManager.resolveMode(taskContext.taskType);

    try {
      const [rawTools, context] = await Promise.all([
        this.upstreamClient.listTools(),
        this.getEnrichmentContext(taskContext.taskType, taskContext.customerId, taskContext.agentId, mode),
      ]);

      const enriched = enrichToolList(rawTools, context);

      // Inject virtual li_recommend tool (only in non-bootstrap modes)
      if (mode !== 'bootstrap') {
        enriched.push(createLiRecommendTool());
      }

      // Sort: ranked first, then alphabetically
      enriched.sort((a, b) => {
        const rankA = a.annotations?.ranking ?? 999;
        const rankB = b.annotations?.ranking ?? 999;
        if (rankA !== rankB) return rankA - rankB;
        return a.name.localeCompare(b.name);
      });

      log.debug('tools/list enriched', {
        count: enriched.length,
        mode,
        taskType: taskContext.taskType,
      });

      return enriched;
    } catch (err) {
      log.error('tools/list failed', { error: err instanceof Error ? err.message : String(err) });
      // Degrade: return raw tools with no enrichment
      try {
        const rawTools = await this.upstreamClient.listTools();
        return rawTools.map((t) => ({
          name: t.name,
          description: t.description,
          inputSchema: t.inputSchema,
          upstreamName: t.upstreamName,
        }));
      } catch {
        return [];
      }
    }
  }

  // ── tools/call handler ───────────────────────────────────

  async handleCallTool(
    toolName: string,
    args: Record<string, unknown>,
    taskContext: { taskType: string; customerId: string; agentId: string },
  ): Promise<UpstreamCallResult> {
    const decisionId = generateDecisionId(taskContext.agentId);
    const mode = this.modeManager.resolveMode(taskContext.taskType);
    const startMs = Date.now();

    // Handle virtual li_recommend tool (delegated to li-recommend-tool.ts)
    if (toolName === 'li_recommend') {
      return handleLiRecommend(
        this.liApi,
        taskContext.taskType,
        taskContext.customerId,
        taskContext.agentId,
      );
    }

    // Determine which tool to execute (auto-mode may reroute)
    let executedAction = toolName;
    let originalAction = toolName;
    let rerouted = false;
    let enrichmentScores: Record<string, number> = {};

    if (mode === 'auto' && !this.config.shadowMode) {
      try {
        const [scores, policy] = await Promise.all([
          this.scoreFetcher.getScores(taskContext.taskType, taskContext.customerId, taskContext.agentId),
          this.liApi.getPolicyDecision(taskContext.taskType, taskContext.customerId, taskContext.agentId),
        ]);

        for (const s of scores) {
          enrichmentScores[s.actionName] = s.compositeScore;
        }

        if (
          policy &&
          policy.confidence >= REROUTE_CONFIDENCE_THRESHOLD &&
          policy.action !== toolName &&
          this.registry.isHealthy(this.resolveUpstream(policy.action))
        ) {
          originalAction = toolName;
          executedAction = policy.action;
          rerouted = true;
          log.info('Auto-mode reroute', {
            decisionId,
            from: toolName,
            to: policy.action,
            confidence: policy.confidence,
            reason: policy.reason,
          });
        }
      } catch {
        // Degrade — continue with original tool
      }
    }

    // Resolve upstream from tool name
    const upstreamName = this.resolveUpstream(executedAction);

    // Proxy to upstream
    const result = await this.upstreamClient.callTool(upstreamName, executedAction, args);

    // Fire-and-forget outcome logging
    const latencyMs = Date.now() - startMs;
    void this.logDecision({
      decisionId,
      agentId: taskContext.agentId,
      customerId: taskContext.customerId,
      taskType: taskContext.taskType,
      actionName: executedAction,
      upstreamName,
      originalAction,
      executedAction,
      mode,
      rerouted,
      enrichmentScores,
      latencyMs,
      args,
      result,
      isError: result.isError === true,
    });

    return result;
  }

  // ── Shutdown ─────────────────────────────────────────────

  async shutdown(): Promise<void> {
    this.registry.stopHealthChecks();
    log.info('Gateway proxy shut down');
  }

  // ── Private: enrichment context ──────────────────────────

  private async getEnrichmentContext(
    taskType: string,
    customerId: string,
    agentId: string,
    mode: GatewayMode,
  ): Promise<EnrichmentContext> {
    // Bootstrap mode — no enrichment needed
    if (mode === 'bootstrap') {
      return {
        taskType,
        customerId,
        agentId,
        mode,
        scores: [],
        policyDecision: null,
      };
    }

    try {
      const [scores, policyDecision] = await Promise.all([
        this.scoreFetcher.getScores(taskType, customerId, agentId),
        this.liApi.getPolicyDecision(taskType, customerId, agentId),
      ]);

      return { taskType, customerId, agentId, mode, scores, policyDecision };
    } catch (err) {
      log.warn('Enrichment context fetch failed — degrading to bootstrap-like', {
        error: err instanceof Error ? err.message : String(err),
      });
      return {
        taskType,
        customerId,
        agentId,
        mode,
        scores: [],
        policyDecision: null,
      };
    }
  }

  // ── Private: routing helpers ─────────────────────────────

  private resolveUpstream(toolName: string): string {
    const entries = this.registry.getAllUpstreams();

    // Match tool name to upstream by prefix convention:
    // "github_push_fix" → upstream named "github"
    // "database_query" → upstream named "database"
    const prefix = toolName.split('_')[0];
    if (prefix) {
      const matched = entries.find(
        (e) => e.server.name === prefix && this.registry.isHealthy(e.server.name),
      );
      if (matched) return matched.server.name;
    }

    // Fallback: first healthy upstream
    for (const entry of entries) {
      if (this.registry.isHealthy(entry.server.name)) return entry.server.name;
    }
    return entries[0]?.server.name ?? 'unknown';
  }

  private async logDecision(record: {
    decisionId: string;
    agentId: string;
    customerId: string;
    taskType: string;
    actionName: string;
    upstreamName: string;
    originalAction: string;
    executedAction: string;
    mode: GatewayMode;
    rerouted: boolean;
    enrichmentScores: Record<string, number>;
    latencyMs: number;
    args?: Record<string, unknown>;
    result?: UpstreamCallResult;
    isError?: boolean;
  }): Promise<void> {
    try {
      // ── LLM classification (fire-and-forget, non-blocking) ────
      let classification: OutcomeClassification | null = null;
      if (this.classifier && record.result) {
        try {
          classification = await this.classifier.classify(
            record.actionName,
            record.args ?? {},
            record.result,
            record.isError ?? false,
            record.taskType,
          );
        } catch {
          // LLM failed — continue with defaults
        }
      }

      // ── Merge: agent-explicit > LLM-inferred > defaults ──────
      const mergedTaskType = resolveMergeField(
        record.taskType,
        classification?.task_type ?? null,
        { exclude: new Set(['unknown', '', 'unspecified_issue']) },
      ) ?? 'unspecified_issue';

      const mergedSuccess = record.isError === true ? false : (classification?.success ?? true);

      // Build API-compatible payload. Omit decision_id — the gateway's
      // dec_ format is non-UUID and the API's schema accepts UUID only.
      const payload: OutcomePayload = {
        agent_id: record.agentId,
        customer_id: record.customerId,
        issue_type: mergedTaskType,
        action_name: record.actionName,
        upstream_name: record.upstreamName,
        original_action: record.originalAction,
        executed_action: record.executedAction,
        mode: record.mode,
        rerouted: record.rerouted,
        success: mergedSuccess,
        response_time_ms: record.latencyMs,
        timestamp: new Date().toISOString(),
        ingestion_source: 'mcp',
        environment: this.config.environment,
      };

      // Attach classifier enrichment if available
      if (classification) {
        payload.context = classification.context;
        payload.error_message = classification.error_message;
        payload.result_summary = classification.result_summary;
        payload.business_outcome = classification.business_outcome;
        payload.classification_confidence = classification.confidence;
      }

      const sent = await this.liApi.logOutcome(payload);
      if (!sent) {
        await enqueueOutcome(payload);
      }
    } catch {
      // Fire-and-forget — silent failure is acceptable
      log.debug('Outcome logging skipped (non-critical)');
    }
  }
}

