34	// ── Shared Types ──
35	
36	export interface WebhookCallbackParams {
37	  decisionId: string;
38	  /** 2 = session outcome, 3 = business outcome. */
39	  layer: 2 | 3;
40	  success: boolean;
41	  score: number;
42	  reason?: string;
43	  metadata?: Record<string, unknown>;
44	  timestamp: string;
45	}
46	
47	export interface WebhookCallbackResult {
48	  resolved: boolean;
49	  outcomeId: string | null;
50	  idempotent: boolean;
51	  layer: 2 | 3;
52	  previousScore: number | null;
53	  newScore: number;
54	}
55	
56	export interface OrchestratorParams {
57	    agentId: string;
58	    customerId: string;
59	    outcomeId: string;
60	    actionId: string;
61	    actionName: string;
62	    contextId: string;
63	    issueType: string;
64	    finalSuccess: boolean;
65	    finalOutcomeScore: number | null;
66	    responseMs?: number | null;
67	    episodeId?: string;
68	    businessOutcome?: string;
69	    errorCode?: string | null;
70	    decisionId?: string;
71	    decisionRecord?: any;
72	    signalConfidence?: number | null;
73	    /**
74	     * When true, the trust-update task is skipped entirely.
75	     * Set by the import route — imported historical rows must never
76	     * affect agent trust scores (trust only reflects live SDK signal).
77	     */
78	    skipTrust?: boolean;
79	}
80	
81	// ── Orchestrator Main Entrypoint ──
82	export async function orchestrateOutcome(params: OrchestratorParams): Promise<void> {
83	
84	    async function taskTrustUpdate() {
85	        // IMPORT GUARD: imported historical rows must never update agent trust.
86	        // Trust reflects live SDK signal only. skipTrust is set by the import route.
87	        if (params.skipTrust === true) return;
88	        await updateAgentTrust(params.agentId, params.customerId, params.finalSuccess,
89	            params.actionName, params.signalConfidence ?? null);
90	    }
91	
92	    async function taskContextDrift() {
93	        await detectContextDrift(supabase, params.customerId, params.issueType, params.agentId);
94	    }
95	
96	    async function taskSilentFailure() {
97	        await detectSilentFailure(supabase, {
98	            outcome_id: params.outcomeId,
99	            customer_id: params.customerId,
100	            agent_id: params.agentId,
101	            action_id: params.actionId,
102	            action_name: params.actionName,
103	            success: params.finalSuccess,
104	            outcome_score: params.finalOutcomeScore,
105	            business_outcome: params.businessOutcome ?? null,
106	            error_code: params.errorCode ?? null,
107	        });
108	    }
109	
110	    async function taskCounterfactuals() {
111	        if (params.decisionRecord?.ranked_actions) {
112	            const outcomeScore = params.finalOutcomeScore ?? (params.finalSuccess ? 1.0 : 0.0);
113	            await writeCounterfactuals({
114	                decisionId: params.decisionId!,
115	                realOutcomeId: params.outcomeId,
116	                realOutcomeScore: outcomeScore,
117	                chosenActionName: params.actionName,
118	                rankedActions: params.decisionRecord.ranked_actions,
119	                contextHash: params.decisionRecord.context_hash ?? '',
120	                episodePosition: params.decisionRecord.episode_position ?? 0,
121	            });
122	        }
123	    }
124	
125	    async function taskSequence() {
126	        if (params.episodeId) {
127	            await upsertSequence({
128	                episodeId: params.episodeId,
129	                agentId: params.agentId,
130	                customerId: params.customerId,
131	                contextHash: params.decisionRecord?.context_hash ?? `${params.contextId}:${params.issueType}`,
132	                actionName: params.actionName,
133	                responseMs: params.responseMs ?? undefined,
134	            });
135	
136	            if (params.businessOutcome === 'resolved' || params.businessOutcome === 'failed') {
137	                const finalScore = params.finalOutcomeScore ?? (params.finalSuccess ? 1.0 : 0.0);
138	                await closeSequence({
139	                    episodeId: params.episodeId,
140	                    agentId: params.agentId,
141	                    customerId: params.customerId,
142	                    finalOutcome: finalScore,
143	                });
144	
145	                await backpropagateReward({
146	                    episode_id: params.episodeId,
147	                    customer_id: params.customerId,
148	                    final_outcome: finalScore,
149	                    gamma: 0.85,
150	                });
151	            }
152	        }
153	    }
154	
155	    async function taskLatencySpike(): Promise<void> {
156	        const { data: recentOutcomes } = await supabase
157	            .from('fact_outcomes')
158	            .select('response_time_ms')
159	            .eq('agent_id', params.agentId)
160	            .eq('action_id', params.actionId)
161	            .order('timestamp', { ascending: false })
162	            .limit(20);
163	
164	        if (!recentOutcomes || recentOutcomes.length < 5) return;
165	
166	        const current = recentOutcomes[0].response_time_ms;
167	        if (!current || current <= 0) return;
168	
169	        const baselineValues = recentOutcomes
170	            .slice(1, 16)
171	            .map((r) => r.response_time_ms)
172	            .filter((v): v is number => typeof v === 'number' && v > 0)
173	            .sort((a, b) => a - b);
174	
175	        if (baselineValues.length < 3) return;
176	
177	        const mid = Math.floor(baselineValues.length / 2);
178	        const median = baselineValues[mid]!;
179	
180	        // 3× multiplier + 1000ms absolute floor prevents false positives
181	        // (e.g. an action that normally takes 50ms spiking to 200ms is not worth alerting on)
182	        if (current <= median * 3 || current <= 1000) return;
183	
184	        // Deduplicate: skip if a latency_spike alert already exists for
185	        // this (customer_id, action_id) in the last hour
186	        const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();
187	        const { data: existing } = await supabase
188	            .from('degradation_alert_events')
189	            .select('id')
190	            .eq('customer_id', params.customerId)
191	            .eq('action_id', params.actionId)
192	            .eq('alert_type', 'latency_spike')
193	            .gte('created_at', oneHourAgo)
194	            .limit(1);
195	
196	        if (existing && existing.length > 0) return;
197	
198	        await supabase.from('degradation_alert_events').insert({
199	            customer_id: params.customerId,
200	            agent_id: params.agentId,
201	            action_id: params.actionId,
202	            alert_type: 'latency_spike',
203	            severity: 'warning',
204	            message:
205	                `Latency spike detected on action "${params.actionName}". ` +
206	                `Current response time: ${current}ms vs median baseline: ${median}ms ` +
207	                `(${(current / median).toFixed(1)}× normal).`,
208	        });
209	    }
210	
211	    async function taskCacheInvalidation() {
212	        // Invalidate only this customer/context score cache entry so the next
213	        // getScores() call reads fresh data instead of serving a stale 5-min TTL entry.
214	        invalidateCache(params.customerId, params.contextId);
215	    }
216	
217	    async function taskPredictiveDrift(): Promise<void> {
218	        // Predictive drift only runs for live SDK outcomes, not imports.
219	        if (params.skipTrust === true) return;
220	        await predictDrift(
221	            params.actionId,
222	            params.customerId,
223	            params.agentId,
224	            params.actionName,
225	        );
226	    }
227	
228	    // Trust atomicity is guaranteed by the update_trust_and_audit() RPC (migration 062),
229	    // which writes both the trust score UPDATE and audit INSERT in one DB transaction.
230	    // Surfacing trust failures as HTTP 500 to agents is counterproductive — a trust DB
231	    // issue should not block outcome logging entirely. Run all tasks via allSettled.
232	    const results = await Promise.allSettled([
233	        taskTrustUpdate(),
234	        taskContextDrift(),
235	        taskSilentFailure(),
236	        taskCounterfactuals(),
237	        taskSequence(),
238	        taskLatencySpike(),
239	        taskCacheInvalidation(),
240	        taskPredictiveDrift(),
241	    ]);
242	
243	    const taskNames = [
244	        'trust-update',
245	        'context-drift',
246	        'silent-failure',
247	        'counterfactuals',
248	        'sequence',
249	        'latency-spike',
250	        'cache-invalidation',
251	        'predictive-drift',
252	    ];
253	
254	    const criticalTaskFailures: string[] = [];
255	
256	    results.forEach((result, index) => {
257	        if (result.status === 'rejected') {
258	            const taskName = taskNames[index];
259	            const errorMessage = (result.reason as Error)?.message ?? String(result.reason);
260	
261	            console.error(`[orchestrator:${taskName}] failed`, {
262	                error: errorMessage,
263	                outcomeId: params.outcomeId,
264	                agentId: params.agentId,
265	            });
266	
267	            if (taskName === 'trust-update' || taskName === 'counterfactuals') {
268	                criticalTaskFailures.push(
269	                    `${taskName} failed for outcome_id=${params.outcomeId} agent_id=${params.agentId}: ${errorMessage}`
270	                );
271	            }
272	        }
273	    });
274	
275	    if (criticalTaskFailures.length > 0) {
276	        void Promise.resolve(supabase.from('degradation_alert_events').insert({
277	            customer_id: params.customerId,
278	            agent_id: params.agentId,
279	            alert_type: 'orchestrator_failure',
280	            severity: 'critical',
281	            message: criticalTaskFailures.join(' | '),
282	        })).catch(() => { });
283	    }
284	
285	    // Non-blocking: refresh trust cache row for dashboard reads.
286	    // Trust score/status authority is updateAgentTrust() via update_trust_and_audit RPC.
287	    // IMPORT GUARD: skip for imported rows — trust reflects SDK signal only.
288	    if (params.skipTrust !== true) {
289	        refreshLiveTrustCache(params.agentId).catch((err) =>
290	            console.warn('[orchestrator] refreshLiveTrustCache failed:', (err as Error).message)
291	        );
292	    }
293	}
294	
295	// ══════════════════════════════════════════════════════════════
296	// Webhook Callback Handler — Layer 2/3 Score Overwrite
297	// ══════════════════════════════════════════════════════════════
298	//
299	// 3-Layer Outcome Score Model:
300	//   Layer 1 (technical): Initial score from gateway inference
301	//   Layer 2 (session):    Webhook callback overwrites score
302	//   Layer 3 (business):   Webhook callback overwrites again
303	//
304	// Append-only log (webhook_callback_log) preserves full timeline —
305	// all three writes are recorded immutably. The latest write per layer
306	// is authoritative for scoring.
307	//
308	// Idempotency: duplicate (decision_id, layer) → returns existing result.
309	// ══════════════════════════════════════════════════════════════
310	
311	export async function handleWebhookCallback(
312	  params: WebhookCallbackParams,
313	): Promise<WebhookCallbackResult> {
314	  // ── 1. Idempotency check ──────────────────────────────────
315	  const { data: existingLog } = await supabase
316	    .from('webhook_callback_log')
317	    .select('outcome_id, previous_score, new_score')
318	    .eq('decision_id', params.decisionId)
319	    .eq('layer', params.layer)
320	    .order('received_at', { ascending: false })
321	    .limit(1)
322	    .maybeSingle();
323	
324	  if (existingLog) {
325	    return {
326	      resolved: true,
327	      outcomeId: existingLog.outcome_id,
328	      idempotent: true,
329	      layer: params.layer,
330	      previousScore: existingLog.previous_score,
331	      newScore: existingLog.new_score,
332	    };
333	  }
334	
335	  // ── 2. Resolve decision_id → outcome ──────────────────────
336	  const { data: outcome } = await supabase
337	    .from('fact_outcomes')
338	    .select('outcome_id, customer_id, outcome_score, success')
339	    .eq('decision_id', params.decisionId)
340	    .order('timestamp', { ascending: false })
341	    .limit(1)
342	    .maybeSingle();
343	
344	  if (!outcome) {
345	    return {
346	      resolved: false,
347	      outcomeId: null,
348	      idempotent: false,
349	      layer: params.layer,
350	      previousScore: null,
351	      newScore: params.score,
352	    };
353	  }
354	
355	  const previousScore = typeof outcome.outcome_score === 'number'
356	    ? outcome.outcome_score
357	    : null;
358	  const newScore = clamp01Score(params.score);
359	
360	  // ── 3. Update fact_outcomes with new score ─────────────────
361	  const nowIso = new Date().toISOString();
362	  const updateData: Record<string, unknown> = {
363	    outcome_score: newScore,
364	    feedback_received_at: nowIso,
365	    signal_updated_at: nowIso,
366	  };
367	
368	  // Layer 3 (business) also updates business_outcome
369	  if (params.layer === 3) {
370	    updateData.business_outcome = params.success ? 'resolved' : 'failed';
371	  }
372	
373	  const { error: updateError } = await supabase
374	    .from('fact_outcomes')
375	    .update(updateData)
376	    .eq('outcome_id', outcome.outcome_id)
377	    .eq('customer_id', outcome.customer_id);
378	
379	  if (updateError) {
380	    console.error('[orchestrator:webhook-callback] outcome update failed:', updateError.message);
381	    throw new Error(`Failed to update outcome ${outcome.outcome_id}: ${updateError.message}`);
382	  }
383	
384	  // ── 4. Write append-only log ──────────────────────────────
385	  const logEntry = {
386	    decision_id: params.decisionId,
387	    outcome_id: outcome.outcome_id,
388	    customer_id: outcome.customer_id,
389	    layer: params.layer,
390	    success: params.success,
391	    previous_score: previousScore,
392	    new_score: newScore,
393	    reason: params.reason ?? null,
394	    metadata: params.metadata ?? null,
395	    webhook_timestamp: params.timestamp,
396	    received_at: nowIso,
397	  };
398	
399	  const { error: logError } = await supabase
400	    .from('webhook_callback_log')
401	    .insert(logEntry);
402	
403	  if (logError) {
404	    // Log write is best-effort — score update already committed.
405	    // Duplicate key on (decision_id, layer) is handled by idempotency check above.
406	    console.warn('[orchestrator:webhook-callback] append-log write failed:', logError.message);
407	  }
408	
409	  // ── 5. Invalidate caches ──────────────────────────────────
410	  invalidateCache(outcome.customer_id, params.decisionId);
411	
412	  return {
413	    resolved: true,
414	    outcomeId: outcome.outcome_id,
415	    idempotent: false,
416	    layer: params.layer,
417	    previousScore,
418	    newScore,
419	  };
420	}
421	
422	function clamp01Score(value: number): number {
423	  if (!Number.isFinite(value)) return 0.5;
424	  if (value < 0) return 0;
425	  if (value > 1) return 1;
426	  return value;
427	}
428	
429	// ── Live Trust Cache Refresh (fire-and-forget) ──
430	// Read-only for existing rows: never recomputes trust score/status.
431	// Bootstrap-only write: inserts a neutral row if the trigger-minted row is missing.
432	async function refreshLiveTrustCache(
433	    agentId: string,
434	): Promise<void> {
435	    const { data: trustRow, error } = await supabase
436	        .from('agent_trust_scores')
437	        .select('agent_id, trust_score, trust_status, total_decisions, consecutive_failures')
438	        .eq('agent_id', agentId)
439	        .maybeSingle();
440	
441	    if (error) {
442	        console.warn('[trust] refreshLiveTrustCache: failed to read agent_trust_scores:', error.message);
443	        return;
444	    }
445	
446	    if (trustRow) {
447	        return;
448	    }
449	
450	    const { error: bootstrapError } = await supabase
451	        .from('agent_trust_scores')
452	        .upsert({
453	            agent_id: agentId,
454	            trust_score: null,
455	            trust_status: 'new',
456	            consecutive_failures: 0,
457	            total_decisions: 0,
458	            updated_at: new Date().toISOString(),
459	        }, { onConflict: 'agent_id' });
460	
461	    if (bootstrapError) {
462	        console.warn(
463	            '[trust] refreshLiveTrustCache: failed to bootstrap missing trust row:',
464	            bootstrapError.message,
465	        );
466	    }
467	}
468	
469	// ── Trust Snapshot (fire-and-forget) ──────────────────────────
470	async function snapshotTrust(
471	    agentId: string,
472	    trust: { trust_score: number; trust_status: string; consecutive_failures: number },
473	    reason: 'pre_failure' | 'pre_incident' | 'manual',
474	    incidentId?: string,
475	): Promise<void> {
476	    await supabase.from('agent_trust_snapshots').insert({
477	        agent_id: agentId,
478	        trust_score: trust.trust_score,
479	        trust_status: trust.trust_status,
480	        consecutive_failures: trust.consecutive_failures,
481	        snapshot_reason: reason,
482	        incident_id: incidentId ?? null,
483	    });
484	}
485	
486	/**
487	 * Updates agent trust score using exponential smoothing.
488	 *
489	 * Formula:
490	 *   On success: new_score = min(score × 1.03, 1.0)
491	 *               consecutive_failures reset to 0
492	 *   On failure: new_score = score × (0.9 ^ consecutive_failures)
493	 *               consecutive_failures incremented
494	 *
495	 * Status thresholds:
496	 *   score >= 0.6                       → trusted
497	 *   score 0.3–0.6                      → probation
498	 *   score 0.1–0.3 OR failures >= 5     → sandbox
499	 *   score < 0.1  OR failures >= 10     → suspended
500	 *
501	 * Cold-start prior: 0.70 (set on first DB insert by account-setup trigger).
502	 * First real outcome moves score to ~0.721 (success) or ~0.567 (failure).
503	 *
504	 * Note: scoring.ts uses a separate Bayesian (Laplace) smoothing formula for
505	 * composite action scores (computeCompositeScore). These are independent calculations.
506	 * This function uses exponential smoothing only.
507	 */
508	async function updateAgentTrust(
509	    agentId: string,
510	    customerId: string,
511	    success: boolean,
512	    actionName?: string,
513	    signalConfidence?: number | null,
514	): Promise<void> {
515	    const { data: trust } = await supabase
516	        .from('agent_trust_scores')
517	        .select('trust_id, trust_score, total_decisions, correct_decisions, consecutive_failures, trust_status, suspension_reason')
518	        .eq('agent_id', agentId)
519	        .maybeSingle();
520	
521	    if (!trust) {
522	        // The fn_init_agent_trust() trigger (migration 058) should
523	        // have created this row. If it's missing, throw so the
524	        // orchestrator's allSettled logs a [trust-update] error.
525	        // Do NOT silently return - a missing row is a data integrity issue.
526	        throw new Error(
527	            `[trust] No agent_trust_scores row for agent_id=${agentId}. ` +
528	            `Trigger fn_init_agent_trust may have failed at agent creation.`
529	        );
530	    }
531	
532	    const currentScore = typeof trust.trust_score === 'number' ? trust.trust_score : 0.7;
533	    const currentTotalDecisions = typeof trust.total_decisions === 'number' ? trust.total_decisions : 0;
534	    const currentCorrectDecisions = typeof trust.correct_decisions === 'number' ? trust.correct_decisions : 0;
535	    const currentFailures = typeof trust.consecutive_failures === 'number' ? trust.consecutive_failures : 0;
536	    const currentStatus = typeof trust.trust_status === 'string' ? trust.trust_status : 'trusted';
537	    const currentSuspensionReason = typeof trust.suspension_reason === 'string' ? trust.suspension_reason : null;
538	
539	    // Always capture old values before any mutation.
540	    // These are written to every audit row so the dashboard can show
541	    // the score delta for each event in the Trust History timeline.
542	    const oldScore = currentScore;
543	    const oldStatus = currentStatus;
544	
545	    let newScore: number;
546	    let newFailures: number;
547	    let newCorrect = currentCorrectDecisions;
548	
549	    if (success) {
550	        newFailures = 0;
551	        newCorrect += 1;
552	        // ── Phase 1: Signal confidence weighting ──────────────
553	        // High-confidence signals (e.g. Stripe webhooks, explicit SDK)
554	        // contribute the full 3% growth. Low-confidence signals (e.g.
555	        // LLM evaluation at 0.3) contribute proportionally less.
556	        // When signalConfidence is null/1.0 → 1 + 0.03*1.0 = 1.03 (unchanged).
557	        const confidence = signalConfidence ?? 1.0;
558	        newScore = Math.min(currentScore * (1 + 0.03 * confidence), 1.0);
559	    } else {
560	        // ── Coordinated Failure Interlock ──────────────────────
561	        // Check if this failure is infrastructure-attributed before
562	        // applying decay. detect_coordinated_failures() looks for 3+
563	        // agents failing the same action within the last 5 minutes.
564	        let isInfrastructureFailure = false;
565	        if (actionName) {
566	            try {
567	                const { data: coordFailures, error: coordError } = await supabase.rpc('detect_coordinated_failures', {
568	                    window_minutes: 5,
569	                    min_agent_count: 3,
570	                });
571	                if (coordError) throw new Error(coordError.message);
