function resolveMergeField(
  agentValue: string,
  llmValue: string | null,
  opts?: { exclude?: Set<string> },
): string | null {
  const exclude = opts?.exclude;
  if (agentValue && !exclude?.has(agentValue)) return agentValue;
  if (llmValue && !exclude?.has(llmValue)) return llmValue;
  return null;
}

