}

/**
 * LayerInfinite MCP Server — outcome-classifier.ts
 * ══════════════════════════════════════════════════════════════
 * LLM-based outcome classifier using GPT-4o mini. Classifies raw
 * tool calls into structured OutcomeClassification when the agent
 * does not provide explicit task_type / context / business_outcome.
 *
 * Fail-open: LLM timeout or error → null (caller falls back to
 * existing rule-based defaults). Never blocks the gateway.
 * ══════════════════════════════════════════════════════════════
 */

import { createHash } from 'node:crypto';
import type { ClassifierConfig } from './config.js';
import type { OutcomeClassification } from './types.js';
import type { UpstreamCallResult } from './rest-client.js';
import { logger } from './logger.js';

const log = logger.forTool('outcome-classifier');

const SYSTEM_PROMPT = [
  'You are an outcome classifier. Given a tool call and its result, extract structured fields.',
  'Classify the task_type from this taxonomy: payment_failed, refund_processing, subscription_management, ticket_resolution, auth_recovery, order_recovery, onboarding, code_deployment, data_query, content_generation, web_search, file_operation, system_diagnostic, unspecified_issue.',
  'Determine business_outcome: resolved (success), partial (mixed/partial success), failed (error/unsuccessful), unknown (unclear).',
  'Output ONLY valid JSON matching the schema. No explanation.',
].join(' ');

const TAXONOMY = new Set([
  'payment_failed', 'refund_processing', 'subscription_management',
  'ticket_resolution', 'auth_recovery', 'order_recovery',
  'onboarding', 'code_deployment', 'data_query', 'content_generation',
  'web_search', 'file_operation', 'system_diagnostic', 'unspecified_issue',
]);

const VALID_OUTCOMES = new Set(['resolved', 'partial', 'failed', 'unknown']);

// ── Helpers ────────────────────────────────────────────────────

function truncateResult(result: UpstreamCallResult, maxChars: number): string {
  const texts: string[] = [];
  for (const item of result.content) {
    if (typeof item.text === 'string') texts.push(item.text);
    else if (typeof item.data === 'string') texts.push(item.data);
    else texts.push(JSON.stringify(item));
  }
  let joined = texts.join('\n');
  if (joined.length > maxChars) {
    joined = joined.slice(0, maxChars) + '…';
  }
  return joined;
}

function makeSignature(toolName: string, args: Record<string, unknown>): string {
  const normalized = JSON.stringify(args, Object.keys(args).sort());
  const hash = createHash('sha256').update(`${toolName}:${normalized}`).digest('hex');
  return hash.slice(0, 16);
}

function isValidClassification(o: unknown): o is OutcomeClassification {
  if (!o || typeof o !== 'object') return false;
  const c = o as Record<string, unknown>;
  return (
    typeof c.task_type === 'string' &&
    TAXONOMY.has(c.task_type) &&
    typeof c.context === 'string' &&
    typeof c.success === 'boolean' &&
    (c.error_message === null || typeof c.error_message === 'string') &&
    typeof c.result_summary === 'string' &&
    typeof c.business_outcome === 'string' &&
    VALID_OUTCOMES.has(c.business_outcome) &&
    typeof c.confidence === 'number' &&
    c.confidence >= 0 &&
    c.confidence <= 1
  );
}

// ── Rule-based fallback classifier ───────────────────────────

const ERROR_KEYWORDS = /\b(?:error|failed|denied|refused|invalid|timeout|unauthorized|forbidden|not.?found|conflict|unavailable|panic|fatal|crash)\b/i;

/**
 * Rule-based classification when the LLM is unreachable.
 * Less accurate but always available — fail-open design.
 * Confidence is always 0.5 (neutral — rules are uncertain by nature).
 */
export function classifyWithRules(
  toolName: string,
  _args: Record<string, unknown>,
  result: { content: Array<{ type: string; [key: string]: unknown }>; isError?: boolean },
  isError: boolean,
  agentTaskType: string,
): OutcomeClassification {
  const resultText = result.content
    .map((item) => (typeof item.text === 'string' ? item.text : JSON.stringify(item)))
    .join('\n');

  const isExplicitTaskType = agentTaskType !== 'unknown'
    && agentTaskType !== ''
    && agentTaskType !== 'unspecified_issue';

  const task_type = isExplicitTaskType ? agentTaskType : 'unspecified_issue';

  if (isError || result.isError === true) {
    return {
      task_type,
      context: `Tool "${toolName}" returned an error`,
      success: false,
      error_message: resultText.slice(0, 500) || 'Unknown error',
      result_summary: `Call to ${toolName} failed`,
      business_outcome: 'failed',
      confidence: 0.5,
    };
  }

  if (ERROR_KEYWORDS.test(resultText)) {
    return {
      task_type,
      context: `Tool "${toolName}" result contains error indicators`,
      success: false,
      error_message: resultText.slice(0, 500),
      result_summary: `Call to ${toolName} indicates failure`,
      business_outcome: 'failed',
      confidence: 0.5,
    };
  }

  if (!resultText.trim()) {
    return {
      task_type,
      context: `Tool "${toolName}" returned empty result`,
      success: true,
      error_message: null,
      result_summary: `Call to ${toolName} completed with no output`,
      business_outcome: 'unknown',
      confidence: 0.5,
    };
  }

  return {
    task_type,
    context: `Tool "${toolName}" executed successfully`,
    success: true,
    error_message: null,
    result_summary: resultText.slice(0, 500),
    business_outcome: 'resolved',
    confidence: 0.5,
  };
}

// ══════════════════════════════════════════════════════════════
// OutcomeClassifier
// ══════════════════════════════════════════════════════════════

export class OutcomeClassifier {
  private readonly config: ClassifierConfig;
  private readonly cache = new Map<string, { storedAt: number; value: OutcomeClassification }>();
  private readonly inFlight = new Map<string, Promise<OutcomeClassification | null>>();

  constructor(config: ClassifierConfig) {
    this.config = config;
  }

  async classify(
    toolName: string,
    args: Record<string, unknown>,
    result: UpstreamCallResult,
    isError: boolean,
    agentTaskType: string,
  ): Promise<OutcomeClassification | null> {
    // Skip LLM if agent provided a valid explicit task_type
    const isExplicitTaskType = agentTaskType !== 'unknown'
      && agentTaskType !== ''
      && agentTaskType !== 'unspecified_issue';

    if (isExplicitTaskType && !result.isError) {
      return null; // Agent knows best — no LLM needed for healthy calls
    }

    // For error cases, always run classification regardless of agent task_type
    // The LLM can extract error_message and determine business_outcome accurately

    const sig = makeSignature(toolName, args);
    const cacheKey = `${sig}:${isError}`;

    // Check LRU cache
    const cached = this.cache.get(cacheKey);
    if (cached && (Date.now() - cached.storedAt) < this.config.cacheTtlMs) {
      log.debug('Cache hit', { toolName, cacheKey });
      return cached.value;
    }

    // In-flight coalescing
    const inFlight = this.inFlight.get(cacheKey);
    if (inFlight) {
      log.debug('In-flight coalesce', { toolName, cacheKey });
      return inFlight;
    }

    const promise = this.callLLM(toolName, args, result, isError, agentTaskType);
    this.inFlight.set(cacheKey, promise);

    try {
      const classification = await promise;
      if (classification) {
        this.cache.set(cacheKey, { storedAt: Date.now(), value: classification });
      }
      return classification;
    } finally {
      this.inFlight.delete(cacheKey);
    }
  }

  // ── Private ──────────────────────────────────────────────────

  private async callLLM(
    toolName: string,
    args: Record<string, unknown>,
    result: UpstreamCallResult,
    isError: boolean,
    agentTaskType: string,
  ): Promise<OutcomeClassification | null> {
    if (!this.config.apiKey) {
      log.warn('Classifier enabled but no API key configured — skipping');
      return null;
    }

    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), this.config.timeoutMs);

    try {
      const userPrompt = JSON.stringify({
        tool_name: toolName,
        arguments: args,
        result: truncateResult(result, 2000),
        is_error: isError || result.isError === true,
        agent_task_type: agentTaskType,
      });

      const response = await fetch(`${this.config.baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.config.apiKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: this.config.model,
          messages: [
            { role: 'system', content: SYSTEM_PROMPT },
            { role: 'user', content: userPrompt },
          ],
          temperature: 0,
          max_tokens: 1024,
          response_format: { type: 'json_object' },
        }),
        signal: controller.signal,
      });

      if (!response.ok) {
        const text = await response.text().catch(() => '');
        log.warn('LLM API error', { status: response.status, text: text.slice(0, 200) });
        return null;
      }

      const data = (await response.json()) as {
        choices?: Array<{ message?: { content?: string } }>;
      };

      const rawContent = data.choices?.[0]?.message?.content;
      if (!rawContent) {
        log.warn('LLM returned empty response');
        return null;
      }

      let parsed: unknown;
      try {
        parsed = JSON.parse(rawContent);
      } catch {
        log.warn('LLM returned invalid JSON', { raw: rawContent.slice(0, 200) });
        return null;
      }

      if (!isValidClassification(parsed)) {
        log.warn('LLM classification failed validation', { parsed });
        return null;
      }

      log.debug('LLM classified', {
        toolName,
        task_type: parsed.task_type,
        business_outcome: parsed.business_outcome,
        confidence: parsed.confidence,
      });

      return parsed;
    } catch (err) {
      if (err instanceof DOMException && err.name === 'AbortError') {
        log.warn('LLM classification timed out', { timeoutMs: this.config.timeoutMs });
      } else {
        log.warn('LLM classification error', {
          error: err instanceof Error ? err.message : String(err),
        });
      }
      return null;
    } finally {
      clearTimeout(timeout);
      this.pruneCache();
    }
  }

  private pruneCache(): void {
    const cutoff = Date.now() - this.config.cacheTtlMs;
    for (const [key, entry] of this.cache) {
      if (entry.storedAt < cutoff) {
        this.cache.delete(key);
      }
    }
  }
}

/**
 * LayerInfinite MCP Server — fail-open.ts
 * ══════════════════════════════════════════════════════════════
 * 3-Layer failure protection with circuit breaker.
 *
 * Layer 1: Async logging fails → write to local disk queue → retry with backoff
 * Layer 2: LI API unreachable → fail open → agent executes directly → queue on disk
 * Layer 3: Everything fails → agent executes as if LI doesn't exist → zero footprint
 *
 * Circuit breaker: 3 consecutive upstream failures → open for 60s → half-open probe
 * ══════════════════════════════════════════════════════════════
 */

import { writeFile, mkdir, readFile, unlink } from 'node:fs/promises';
import { join } from 'node:path';
import { randomUUID } from 'node:crypto';
import type { FailOpenState, OutcomePayload } from './types.js';
import { logger } from './logger.js';

const log = logger.forTool('fail-open');

const QUEUE_DIR = '.li-queue';
const CIRCUIT_BREAKER_THRESHOLD = 3;
const CIRCUIT_BREAKER_OPEN_MS = 60_000;
const MAX_QUEUE_RETRY_MS = 300_000; // 5 min max retry
const BASE_BACKOFF_MS = 1000;

export function createFailOpenState(): FailOpenState {
  return {
    upstreamFailures: new Map(),
    circuitBreakerOpen: new Map(),
    lastHealthCheck: new Map(),
    totalRequests: 0,
    passthroughRequests: 0,
  };
}

/** Ensure queue directory exists. Returns the directory path. */
async function ensureQueueDir(): Promise<string> {
  await mkdir(QUEUE_DIR, { recursive: true });
  return QUEUE_DIR;
}

// ── Layer 1: Disk queue for failed async logs ────────────────

export interface QueuedEntry {
  id: string;
  payload: OutcomePayload;
  attempts: number;
  firstAttempt: number;
  lastAttempt: number;
}

/**
 * Write an outcome to the local disk queue when LI API is unreachable.
 * Each entry is a separate JSON file for atomicity.
 */
export async function enqueueOutcome(payload: OutcomePayload): Promise<void> {
  const dir = await ensureQueueDir();
  const id = randomUUID();
  const entry: QueuedEntry = {
    id,
    payload,
    attempts: 0,
    firstAttempt: Date.now(),
    lastAttempt: Date.now(),
  };
  const path = join(dir, `${id}.json`);
  await writeFile(path, JSON.stringify(entry) + '\n', 'utf-8');
  log.info('Outcome queued to disk', { id, action: payload.action_name });
}

/** List all queued entries sorted by first attempt (oldest first). */
export async function listQueuedEntries(): Promise<QueuedEntry[]> {
  const { readdir } = await import('node:fs/promises');
  const dir = await ensureQueueDir();
  const entries: QueuedEntry[] = [];
  try {
    const files = await readdir(dir);
    for (const file of files) {
      if (!file.endsWith('.json')) continue;
      try {
        const content = await readFile(join(dir, file), 'utf-8');
        entries.push(JSON.parse(content) as QueuedEntry);
      } catch {
        // Corrupt queue file — skip
      }
    }
  } catch {
    // Directory doesn't exist yet — no entries
  }
  return entries.sort((a, b) => a.firstAttempt - b.firstAttempt);
}

/** Remove a queued entry by ID. */
export async function dequeueEntry(id: string): Promise<void> {
  const dir = await ensureQueueDir();
  try {
    await unlink(join(dir, `${id}.json`));
  } catch {
    // Already removed — fine
  }
}

/** Update attempts on a queued entry. */
export async function updateQueuedEntry(entry: QueuedEntry): Promise<void> {
  const dir = await ensureQueueDir();
  await writeFile(join(dir, `${entry.id}.json`), JSON.stringify(entry) + '\n', 'utf-8');
}

// ── Layer 2 & 3: Circuit breaker ─────────────────────────────

/** Record a failure for an upstream server. Returns true if circuit breaker just opened. */
export function recordUpstreamFailure(state: FailOpenState, upstreamName: string): boolean {
  const current = state.upstreamFailures.get(upstreamName) ?? 0;
  const next = current + 1;
  state.upstreamFailures.set(upstreamName, next);

  if (next >= CIRCUIT_BREAKER_THRESHOLD && !state.circuitBreakerOpen.get(upstreamName)) {
    state.circuitBreakerOpen.set(upstreamName, true);
    log.warn('Circuit breaker opened', { upstream: upstreamName, failures: next });
    return true;
  }
  return false;
}

/** Record a success — resets failure count and closes circuit breaker. */
export function recordUpstreamSuccess(state: FailOpenState, upstreamName: string): void {
  state.upstreamFailures.set(upstreamName, 0);
  if (state.circuitBreakerOpen.get(upstreamName)) {
    state.circuitBreakerOpen.set(upstreamName, false);
    log.info('Circuit breaker closed', { upstream: upstreamName });
  }
}

/** Probe half-open: check if enough time has passed to attempt a probe.
 *  Does NOT reset state — the caller must call recordUpstreamSuccess/Failure
 *  after the actual health check completes. */
export function probeCircuitBreaker(state: FailOpenState, upstreamName: string): boolean {
  const open = state.circuitBreakerOpen.get(upstreamName);
  if (!open) return false;

  const lastCheck = state.lastHealthCheck.get(upstreamName) ?? 0;
  if (Date.now() - lastCheck < CIRCUIT_BREAKER_OPEN_MS) return false;

  // Allow one probe through — caller is responsible for recording result
  state.circuitBreakerOpen.set(upstreamName, false);
  log.info('Circuit breaker half-open — probing', { upstream: upstreamName });
  return true;
}

/** Check if circuit breaker is open for an upstream. */
export function isCircuitOpen(state: FailOpenState, upstreamName: string): boolean {
  return state.circuitBreakerOpen.get(upstreamName) ?? false;
}

/** Update health check timestamp. */
export function updateHealthCheck(state: FailOpenState, upstreamName: string): void {
  state.lastHealthCheck.set(upstreamName, Date.now());
}

// ── Retry queue processor ────────────────────────────────────

export type QueueSender = (payload: OutcomePayload) => Promise<boolean>;

/**
 * Process the disk queue with exponential backoff.
 * Returns the number of entries successfully sent.
 */
export async function processQueue(send: QueueSender): Promise<number> {
  const entries = await listQueuedEntries();
  let sent = 0;

  for (const entry of entries) {
    const elapsed = Date.now() - entry.firstAttempt;
    if (elapsed > MAX_QUEUE_RETRY_MS) {
      log.warn('Queue entry expired', { id: entry.id, elapsed_ms: elapsed });
      await dequeueEntry(entry.id);
      continue;
    }

    const success = await send(entry.payload);
    if (success) {
      await dequeueEntry(entry.id);
      sent++;
    } else {
      const updated: QueuedEntry = {
        ...entry,
        attempts: entry.attempts + 1,
        lastAttempt: Date.now(),
      };
      await updateQueuedEntry(updated);
    }
  }

  return sent;
}

/**
 * Calculate backoff delay for a queue retry.
 * Exponential: min(base * 2^attempts, 5 min).
 */
export function backoffDelay(attempts: number): number {
  return Math.min(BASE_BACKOFF_MS * Math.pow(2, attempts), MAX_QUEUE_RETRY_MS);
}

/** Get queue stats for monitoring. */
export async function getQueueStats(): Promise<{ count: number; oldestMs: number | null }> {
  const entries = await listQueuedEntries();
  return {
    count: entries.length,
    oldestMs: entries.length > 0 ? Date.now() - entries[0].firstAttempt : null,
  };
}

// ── Queue processor lifecycle ────────────────────────────────

/**
 * Start a periodic queue processor. Runs immediately on startup to drain any
 * entries left from a crash, then every `intervalMs` thereafter.
 * Returns a handle with `stop()` for clean shutdown.
 */
export function startQueueProcessor(
  send: QueueSender,
  intervalMs: number = 30_000,
): { stop: () => void } {
  // Drain on startup — catch crash leftovers immediately
  void processQueue(send);

  const timer = setInterval(() => {
    void processQueue(send);
  }, intervalMs);

  log.info('Queue processor started', { intervalMs });

  return {
    stop: () => {
      clearInterval(timer);
      log.info('Queue processor stopped');
    },
  };
}

/**
 * LayerInfinite MCP Server — types.ts
 * ══════════════════════════════════════════════════════════════
 * Shared domain types for the V2 Gateway Proxy.
 * Imports config types from config.ts; defines gateway-specific types here.
 * ══════════════════════════════════════════════════════════════
 */

import type { LIMode } from './config.js';

/** Gateway operating mode (bootstrap = mode null, observe only). */
export type GatewayMode = 'bootstrap' | LIMode;

/** Enriched tool returned by tools/list interception. */
export interface EnrichedTool {
  name: string;
  /** ENRICHED description — original woven with historical context. Never modify inputSchema. */
  description: string;
  /** UNMODIFIED — passthrough from upstream. */
  inputSchema: Record<string, unknown>;
  /** Which upstream server owns this tool. */
  upstreamName: string;
  annotations?: {
    /** 1-based rank within task (best=1). */
    ranking?: number;
    category?: 'recommended' | 'neutral' | 'warning';
  };
}

/** Context gathered before enriching tool descriptions. */
export interface EnrichmentContext {
  taskType: string;
  customerId: string;
  agentId: string;
  mode: GatewayMode;
  scores: ScoredAction[];
  policyDecision: PolicyDecision | null;
}

/** A scored action from the LI scoring engine. */
export interface ScoredAction {
  actionName: string;
  compositeScore: number;
  successRate: number;
  sampleSize: number;
  trendLabel?: string;
}

/** Policy decision from the LI policy engine. */
export interface PolicyDecision {
  action: string;
  reason: string;
  confidence: number;
}

/** A decision record — one tool invocation tracked by the gateway. */
export interface DecisionRecord {
  /** Format: dec_{ts12}_{agent4}_{rand4} — lexicographically sortable. */
  decisionId: string;
  agentId: string;
  customerId: string;
  taskType: string;
  actionName: string;
  upstreamName: string;
  /** What the agent chose. */
  originalAction: string;
  /** What actually ran (may differ in Auto mode). */
  executedAction: string;
  mode: GatewayMode;
  rerouted: boolean;
  enrichmentScores: Record<string, number>;
  /** ISO 8601 timestamp. */
  timestamp: string;
}

/** An episode — a session containing multiple decisions. */
export interface Episode {
  episodeId: string;
  agentId: string;
  sessionStart: string;
  /** Ordered list of decisionIds. */
  decisions: string[];
  /** Max 3 coachings per episode. */
  coachingCount: number;
}

/** Webhook callback from Layer 2 (session) or Layer 3 (business). */
export interface WebhookCallback {
  decisionId: string;
  /** 2 = session outcome, 3 = business outcome. */
  layer: 2 | 3;
  success: boolean;
  reason?: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/** MCP resource definition for gateway resources. */
export interface Resource {
  uri: string;
  name: string;
  description: string;
  mimeType: string;
  handler: () => Promise<{
    contents: Array<{ uri: string; mimeType: string; text: string }>;
  }>;
}

/** MCP prompt definition for gateway prompts. */
export interface Prompt {
  name: string;
  description: string;
  arguments: Array<{ name: string; description?: string; required?: boolean }>;
  handler: () => Promise<{
    messages: Array<{
      role: 'user' | 'assistant';
      content: { type: 'text'; text: string };
    }>;
  }>;
}

/** LLM-inferred outcome classification. Agent-explicit fields override LLM. */
export interface OutcomeClassification {
  task_type: string;
  context: string;
  success: boolean;
  error_message: string | null;
  result_summary: string;
  business_outcome: 'resolved' | 'partial' | 'failed' | 'unknown';
  confidence: number;
}

/** In-memory fail-open state for circuit breaker + health tracking. */
export interface FailOpenState {
  upstreamFailures: Map<string, number>;
  circuitBreakerOpen: Map<string, boolean>;
  lastHealthCheck: Map<string, number>;
  totalRequests: number;
  passthroughRequests: number;
}

/** Outcome payload sent to LI API for logging. Fields match the API's LogOutcomeBody schema. */
export interface OutcomePayload {
  /** Internal decision ID (dec_ format) — NOT sent to API (API expects UUID). */
  decision_id?: string;
  agent_id: string;
  customer_id: string;
  /** Maps to API's `issue_type` field. */
  issue_type: string;
  action_name: string;
  upstream_name: string;
  original_action: string;
  executed_action: string;
  mode: string;
  rerouted: boolean;
  /** Required by API. Defaults to true for fire-and-forget gateway logging. */
  success: boolean;
  /** Maps to API's `response_time_ms` field. */
  response_time_ms: number;
  timestamp: string;
  ingestion_source: 'mcp';
  environment: string;
  /** LLM-inferred: what the tool call was about. */
  context?: string;
  /** LLM-inferred: error message if the tool call failed. */
  error_message?: string | null;
  /** LLM-inferred: human-readable result summary. */
  result_summary?: string;
  /** LLM-inferred: business outcome classification. */
  business_outcome?: string;
  /** LLM-inferred: confidence of the classification (0-1). */
  classification_confidence?: number;
}

