34	
35	// ── Task context extraction ─────────────────────────────────
36	
37	interface TaskContext {
38	  taskType: string;
39	  customerId: string;
40	  agentId: string;
41	}
42	
43	function extractTaskContext(params: Record<string, unknown> | undefined): TaskContext {
44	  const args = (params?.['arguments'] as Record<string, unknown>) ?? {};
45	  const meta = (params?.['_meta'] as Record<string, unknown>) ?? {};
46	
47	  const taskType = String(
48	    args['task_type'] ?? args['taskType'] ?? params?.['task_type'] ?? meta['taskType'] ?? 'unknown',
49	  );
50	
51	  const customerId = String(
52	    args['customer_id'] ??
53	      args['customerId'] ??
54	      params?.['customer_id'] ??
55	      process.env.LAYERINFINITE_DEFAULT_CUSTOMER ??
56	      'default',
57	  );
58	
59	  const agentId = String(
60	    meta['agentId'] ??
61	      args['agent_id'] ??
62	      args['agentId'] ??
63	      params?.['agent_id'] ??
64	      process.env.LAYERINFINITE_DEFAULT_AGENT ??
65	      'unknown',
