/**
 * LayerInfinite MCP Server — enrichment/format-auto.ts
 * ══════════════════════════════════════════════════════════════
 * Auto-mode enrichment formatter. Returns descriptions UNCHANGED
 * — the agent never knows LI exists. Silent rerouting happens at
 * the proxy level only.
 * ══════════════════════════════════════════════════════════════
 */

export function formatAutoEnrichment(originalDescription: string): string {
  return originalDescription;
}

/**
 * LayerInfinite MCP Gateway — resources/dashboard.ts
 * ══════════════════════════════════════════════════════════════
 * Static MCP resource: layerinfinite://dashboard
 *
 * Returns the LayerInfinite dashboard URL so agents can
 * reference or present it to users.
 * ══════════════════════════════════════════════════════════════
 */

import type { Resource } from '../types.js';

const DASHBOARD_URL = process.env.LAYERINFINITE_DASHBOARD_URL ?? 'https://layerinfinite.me/dashboard';

export const dashboardResource: Resource = {
  uri: 'layerinfinite://dashboard',
  name: 'LayerInfinite Dashboard',
  description:
    'The LayerInfinite dashboard provides real-time outcome analytics, ' +
    'trust scores, action performance metrics, model version history, ' +
    'and shadow mode comparison data.',
  mimeType: 'text/plain',
  handler: async () => ({
    contents: [
      {
        uri: 'layerinfinite://dashboard',
        mimeType: 'text/plain',
        text: DASHBOARD_URL,
      },
    ],
  }),
};

/**
 * LayerInfinite MCP Gateway — resources/docs.ts
 * ══════════════════════════════════════════════════════════════
 * Static MCP resource: layerinfinite://docs
 *
 * Returns the LayerInfinite documentation URL so agents can
 * reference integration guides and API documentation.
 * ══════════════════════════════════════════════════════════════
 */

import type { Resource } from '../types.js';

const DOCS_URL = process.env.LAYERINFINITE_DOCS_URL ?? 'https://layerinfinite.me/docs';

export const docsResource: Resource = {
  uri: 'layerinfinite://docs',
  name: 'LayerInfinite Documentation',
  description:
    'LayerInfinite integration guides, MCP gateway configuration, ' +
    'API reference, and troubleshooting documentation.',
  mimeType: 'text/plain',
  handler: async () => ({
    contents: [
      {
        uri: 'layerinfinite://docs',
        mimeType: 'text/plain',
        text: DOCS_URL,
      },
    ],
  }),
};
